Let opposite_functor_involutive_helper (x : cat)
  : (x.1^op^op; has_op (_; has_op _)) = x
    := path_sigma_uncurried
         P
         (((x.1^op)^op)%category;
          has_op ((x.1^op)%category;
                  has_op x))
         x
         (Category.Dual.opposite_involutive x.1;
          path_ishprop _ _).

hypotheses.body:
{|
  object := {C : PreCategory & P C};
  morphism :=
    fun (C : {C : PreCategory & P C}) (D : {C0 : PreCategory & P C0}) =>
    Functor C.1 D.1;
  Core.identity := fun C : {C : PreCategory & P C} => 1;
  Category.Core.compose :=
    fun (s d d' : {C : PreCategory & P C}) (F : Functor d.1 d'.1)
      (G : Functor s.1 d.1) =>
    F o G;
  associativity :=
    fun (x2 x3 x4 x5 : {C : PreCategory & P C}) (m1 : Functor x2.1 x3.1)
      (m2 : Functor x3.1 x4.1) (m3 : Functor x4.1 x5.1) =>
    Laws.associativity m1 m2 m3;
  associativity_sym :=
    fun (x2 x3 x4 x5 : {C : PreCategory & P C}) (m1 : Functor x2.1 x3.1)
      (m2 : Functor x3.1 x4.1) (m3 : Functor x4.1 x5.1) =>
    symmetry (m3 o m2 o m1) (m3 o (m2 o m1)) (Laws.associativity m1 m2 m3);
  left_identity :=
    fun (a b : {C : PreCategory & P C}) (f : Functor a.1 b.1) =>
    Laws.left_identity f;
  right_identity :=
    fun (a b : {C : PreCategory & P C}) (f : Functor a.1 b.1) =>
    Laws.right_identity f;
  identity_identity :=
    fun x2 : {C : PreCategory & P C} => Laws.left_identity 1;
  trunc_morphism := fun s d : {C : PreCategory & P C} => HF s.2 d.2
|}

goals.conclusion:
({|
   object_of := object_of;
   morphism_of := morphism_of;
   composition_of := composition_of;
   identity_of := identity_of
 |}^op)^op =
{|
  object_of := object_of;
  morphism_of := morphism_of;
  composition_of := composition_of;
  identity_of := identity_of
|}

({|
   object_of := object_of;
   morphism_of := morphism_of;
   composition_of := composition_of;
